#include <algorithm>

using namespace std;

long long solve(vector<long long> prices, vector<long long> strategy, long long k) {
    int n = prices.size();
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }

    long long max_profit = original_profit;
    int half_k = k / 2;

    // Precompute the prefix sum of (strategy[i] * prices[i])
    vector<long long> prefix(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix[i + 1] = prefix[i] + strategy[i] * prices[i];
    }

    // Precompute the sum of prices[i] for the second half (sell part)
    vector<long long> sell_sum(n + 2, 0);
    for (int i = 0; i < n; ++i) {
        sell_sum[i + 1] = sell_sum[i] + prices[i];
    }

    for (int i = 0; i <= n - k; ++i) {
        int start = i;
        int end = i + k;
        int mid = start + half_k;

        // Original sum for the window [start, end)
        long long original_window_sum = prefix[end] - prefix[start];

        // New sum: first half is 0 (sum is 0), second half is 1 (sum is sum of prices[mid...end-1])
        long long new_window_sum = (sell_sum[end] - sell_sum[mid]);

        // Calculate the new profit
        long long new_profit = original_profit - original_window_sum + new_window_sum;

        if (new_profit > max_profit) {
            max_profit = new_profit;
        }
    }

    return max_profit;
}
