using namespace std;

long long solve(vector<long long> prices, vector<long long> strategy, long long k) {
    int n = prices.size();
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }

    long long max_profit = original_profit;
    int half_k = k / 2;

    // Precompute the prefix sum of (0 - strategy[i]) * prices[i] for the first half
    // and (1 - strategy[i]) * prices[i] for the second half
    vector<long long> prefix_diff_first(n + 1, 0);
    vector<long long> prefix_diff_second(n + 1, 0);

    for (int i = 0; i < n; ++i) {
        long long diff_first = (0 - strategy[i]) * prices[i];
        long long diff_second = (1 - strategy[i]) * prices[i];
        prefix_diff_first[i + 1] = prefix_diff_first[i] + diff_first;
        prefix_diff_second[i + 1] = prefix_diff_second[i] + diff_second;
    }

    // Sliding window to find the best k-length segment
    for (int i = 0; i + k <= n; ++i) {
        int first_half_end = i + half_k;
        int second_half_end = i + k;

        long long first_half_gain = prefix_diff_first[first_half_end] - prefix_diff_first[i];
        long long second_half_gain = prefix_diff_second[second_half_end] - prefix_diff_second[first_half_end];

        long long total_gain = first_half_gain + second_half_gain;
        max_profit = max(max_profit, original_profit + total_gain);
    }

    return max_profit;
}
