long long solve(vector<long long> prices, vector<long long> strategy, long long k) {
    int n = prices.size();
    long long original_profit = 0;
    for (int i = 0; i < n; ++i) {
        original_profit += strategy[i] * prices[i];
    }

    long long max_profit = original_profit;
    int half_k = k / 2;

    // Precompute the prefix sum of (0 - strategy[i]) * prices[i] for the first half (set to 0)
    vector<long long> prefix_diff_first(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_diff_first[i + 1] = prefix_diff_first[i] + (0 - strategy[i]) * prices[i];
    }

    // Precompute the prefix sum of (1 - strategy[i]) * prices[i] for the second half (set to 1)
    vector<long long> prefix_diff_second(n + 1, 0);
    for (int i = 0; i < n; ++i) {
        prefix_diff_second[i + 1] = prefix_diff_second[i] + (1 - strategy[i]) * prices[i];
    }

    // Sliding window to find the best k-length window
    for (int i = 0; i <= n - k; ++i) {
        int first_half_end = i + half_k;
        int second_half_end = i + k;

        long long first_diff = prefix_diff_first[first_half_end] - prefix_diff_first[i];
        long long second_diff = prefix_diff_second[second_half_end] - prefix_diff_second[first_half_end];

        long long total_diff = first_diff + second_diff;
        max_profit = max(max_profit, original_profit + total_diff);
    }

    return max_profit;
}
